import React from 'react';

const DeltaDiscounts = () => {
  return (
    <div className="p-4">
      <h1 className="text-2xl font-bold mb-4">Delta Discounts</h1>
      <p>Here you can find information about delta discounts.</p>
      <div>
          {chartConfigs.map((config, index) => (
            <DiscountChart 
              key={index}
              tableName={config.tableName}
              title={config.title}
            />
          ))}
        </div>
    </div>
  );
};

export default DeltaDiscounts;
